module up_down_counter_3bit(clk, rst, up_down, obf_Q);
    input clk, rst, up_down;
    output reg [2:0] obf_Q;

    always @(posedge clk) begin
        if (rst)
            obf_Q <= 3'b000;
        else if (up_down)
            obf_Q <= obf_Q + 1;
        else
            obf_Q <= obf_Q - 1;
    end
endmodule
